# scripts/validate_flag_configs.py
"""
CI script: verify that each flag's config is consistent with its state.
Run on every PR that touches flags/flags.yaml.
"""
import sys, yaml
from pathlib import Path
from datetime import date

_TODAY = date.today().isoformat()

def validate_flag(name: str, cfg: dict) -> list[str]:
    errors = []
    state = cfg.get("state", "").lower()

    if state == "created":
        if cfg.get("default") is not False:
            errors.append(f"{name}: state=created requires default=false")
        if cfg.get("allowlist"):
            errors.append(f"{name}: state=created requires empty allowlist")
        if cfg.get("percentage", 0) != 0:
            errors.append(f"{name}: state=created requires percentage=0")

    elif state == "internal":
        if cfg.get("default") is not False:
            errors.append(f"{name}: state=internal requires default=false")
        if cfg.get("percentage", 0) != 0:
            errors.append(f"{name}: state=internal requires percentage=0")
        if not cfg.get("allowlist"):
            errors.append(f"{name}: state=internal requires non-empty allowlist")

    elif state == "canary":
        if cfg.get("default") is not False:
            errors.append(f"{name}: state=canary requires default=false")
        if cfg.get("allowlist"):
            errors.append(f"{name}: state=canary allowlist must be empty")
        pct = cfg.get("percentage", 0)
        if not (1 <= pct <= 50):
            errors.append(f"{name}: state=canary percentage must be 1–50, got {pct}")

    elif state == "ga":
        if cfg.get("default") is not True:
            errors.append(f"{name}: state=ga requires default=true")
        if cfg.get("percentage", 0) != 0:
            errors.append(f"{name}: state=ga requires percentage=0")

    # Deadline check for all states
    deadline = cfg.get("ga_deadline")
    if deadline and deadline < _TODAY and state not in ("ga", "removed"):
        errors.append(
            f"{name}: ga_deadline {deadline} has passed but state={state}; "
            "advance to GA or remove the flag"
        )

    return errors

def main() -> None:
    raw = yaml.safe_load(Path("flags/flags.yaml").read_text()) or {}
    all_errors = []
    for name, cfg in raw.items():
        all_errors.extend(validate_flag(name, cfg))
    if all_errors:
        print("Flag config validation FAILED:")
        for e in all_errors:
            print(f"  {e}")
        sys.exit(1)
    print(f"OK: {len(raw)} flag(s) validated")

if __name__ == "__main__":
    main()

# tests/test_validate_flag_configs.py
import unittest, textwrap, tempfile
from pathlib import Path
from unittest.mock import patch

import scripts.validate_flag_configs as v

def _cfg(state, default=False, allowlist=None, percentage=0, ga_deadline=None):
    """Build a minimal flag config dict."""
    d = {"state": state, "default": default,
         "allowlist": allowlist or [], "percentage": percentage}
    if ga_deadline:
        d["ga_deadline"] = ga_deadline
    return d

class TestValidateFlagConfigs(unittest.TestCase):

    def test_created_valid(self):
        self.assertEqual([], v.validate_flag("f", _cfg("created")))

    def test_created_rejects_default_true(self):
        errors = v.validate_flag("f", _cfg("created", default=True))
        self.assertTrue(any("default=false" in e for e in errors))

    def test_created_rejects_nonempty_allowlist(self):
        errors = v.validate_flag("f", _cfg("created", allowlist=["u1"]))
        self.assertTrue(any("allowlist" in e for e in errors))

    def test_internal_valid(self):
        self.assertEqual([], v.validate_flag("f", _cfg("internal", allowlist=["u1"])))

    def test_internal_rejects_empty_allowlist(self):
        errors = v.validate_flag("f", _cfg("internal", allowlist=[]))
        self.assertTrue(any("allowlist" in e for e in errors))

    def test_canary_valid(self):
        self.assertEqual([], v.validate_flag("f", _cfg("canary", percentage=10)))

    def test_canary_rejects_zero_percentage(self):
        errors = v.validate_flag("f", _cfg("canary", percentage=0))
        self.assertTrue(any("percentage" in e for e in errors))

    def test_canary_rejects_nonempty_allowlist(self):
        errors = v.validate_flag("f", _cfg("canary", percentage=10, allowlist=["u1"]))
        self.assertTrue(any("allowlist" in e for e in errors))

    def test_ga_valid(self):
        self.assertEqual([], v.validate_flag("f", _cfg("ga", default=True)))

    def test_ga_rejects_default_false(self):
        errors = v.validate_flag("f", _cfg("ga", default=False))
        self.assertTrue(any("default=true" in e for e in errors))

    def test_overdue_deadline_raises_error(self):
        # ga_deadline in the past and state is not GA
        errors = v.validate_flag("f", _cfg("canary", percentage=10, ga_deadline="2020-01-01"))
        self.assertTrue(any("overdue" in e.lower() or "passed" in e.lower() for e in errors))

    def test_overdue_deadline_ok_if_ga(self):
        # Even if past deadline, GA state is acceptable
        errors = v.validate_flag("f", _cfg("ga", default=True, ga_deadline="2020-01-01"))
        self.assertEqual([], errors)

if __name__ == "__main__":
    unittest.main()
